const webhookData = $('Webhook').item.json;
const input = webhookData.body || webhookData;
const errors = [];

if (!input.shot_id) errors.push("Missing: shot_id");
if (!input.scene_id) errors.push("Missing: scene_id");
if (!input.image_url) errors.push("Missing: image_url");
if (!input.duration) errors.push("Missing: duration");

const validEffects = [
  'fade_in', 'fade_out', 'fade_in_out',
  'pan_left', 'pan_right', 'pan_up', 'pan_down',
  'opacity_reveal',
  'reveal_pan_right', 'reveal_pan_left', 'reveal_pan_up', 'reveal_pan_down',
  'static', 'custom'
];
const effect = input.effect || 'fade_in_out';
if (effect !== 'custom' && !validEffects.includes(effect)) {
  errors.push(`Invalid effect '${effect}'. Must be one of: ${validEffects.join(', ')}, or 'custom' with ffmpeg_filter`);
}
if (effect === 'custom' && !input.ffmpeg_filter) {
  errors.push("custom effect requires ffmpeg_filter parameter");
}

if (errors.length > 0) {
  throw new Error("Validation failed: " + errors.join(", "));
}

return {
  shot_id: input.shot_id,
  scene_id: input.scene_id,
  image_url: input.image_url,
  duration: parseFloat(input.duration) || 4.0,
  effect: effect,
  ffmpeg_filter: input.ffmpeg_filter || null,
  intensity: input.intensity || 0.15,
  fps: parseInt(input.fps) || 25
};

const input = $input.item.json;
const effect = input.effect;
const duration = input.duration;
const fps = input.fps;
const totalFrames = Math.round(duration * fps);
const w = 1920;
const h = 1080;
const uw = 3840;
const uh = 2160;

if (input.ffmpeg_filter) {
  return { ...input, filter: input.ffmpeg_filter };
}

const presets = {};
presets.fade_in = `[0:v]scale=${w}:${h},fps=${fps},fade=t=in:st=0:d=1,format=yuv420p[v]`;
presets.fade_out = `[0:v]scale=${w}:${h},fps=${fps},fade=t=out:st=${Math.max(0, duration - 1)}:d=1,format=yuv420p[v]`;
presets.fade_in_out = `[0:v]scale=${w}:${h},fps=${fps},fade=t=in:st=0:d=1,fade=t=out:st=${Math.max(0, duration - 1)}:d=1,format=yuv420p[v]`;
presets.opacity_reveal = `[0:v]scale=${uw}:${uh},fps=${fps},format=yuva420p,fade=t=in:st=0:d=2:alpha=1,format=yuv420p[v]`;
presets.static = `[0:v]scale=${w}:${h},fps=${fps},format=yuv420p[v]`;
// Pan effects (use crop on upscaled image)
const panSpeed = input.intensity || 0.25;
presets.pan_left = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2+iw/2*t/${duration}*${panSpeed}':'ih/2-oh/2',fps=${fps},format=yuv420p[v]`;
presets.pan_right = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2-iw/2*t/${duration}*${panSpeed}':'ih/2-oh/2',fps=${fps},format=yuv420p[v]`;
presets.pan_up = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2':'ih/2-oh/2+ih/2*t/${duration}*${panSpeed}',fps=${fps},format=yuv420p[v]`;
presets.pan_down = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2':'ih/2-oh/2-ih/2*t/${duration}*${panSpeed}',fps=${fps},format=yuv420p[v]`;
// Composite: opacity reveal + pan right (2s reveal then 4s pan)
const revealDur = Math.min(2, duration * 0.33);
presets.reveal_pan_right = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2-iw/4*t/${duration}':'ih/2-oh/2',fps=${fps},format=yuva420p,fade=t=in:st=0:d=${revealDur}:alpha=1,format=yuv420p[v]`;
presets.reveal_pan_left = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2+iw/4*t/${duration}':'ih/2-oh/2',fps=${fps},format=yuva420p,fade=t=in:st=0:d=${revealDur}:alpha=1,format=yuv420p[v]`;
presets.reveal_pan_up = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2':'ih/2-oh/2+ih/4*t/${duration}',fps=${fps},format=yuva420p,fade=t=in:st=0:d=${revealDur}:alpha=1,format=yuv420p[v]`;
presets.reveal_pan_down = `[0:v]scale=${uw}:${uh},crop=${w}:${h}:'iw/2-ow/2':'ih/2-oh/2-ih/4*t/${duration}',fps=${fps},format=yuva420p,fade=t=in:st=0:d=${revealDur}:alpha=1,format=yuv420p[v]`;

const filter = presets[effect] || presets.fade_in_out;
return { ...input, filter };
